import React, { useState } from 'react';
import { BarChart, Bar, LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer, PieChart, Pie, Cell, RadarChart, PolarGrid, PolarAngleAxis, PolarRadiusAxis, Radar } from 'recharts';
import { AlertCircle, CheckCircle, TrendingUp, Activity, FileText, Settings } from 'lucide-react';

// استانداردهای ISO برای آلاینده‌ها (mg/Nm³)
const STANDARDS = {
  CO: { limit: 100, unit: 'mg/Nm³', name: 'مونوکسید کربن' },
  CO2: { limit: 500, unit: 'mg/Nm³', name: 'دی‌اکسید کربن' },
  SO2: { limit: 200, unit: 'mg/Nm³', name: 'دی‌اکسید گوگرد' },
  NOx: { limit: 150, unit: 'mg/Nm³', name: 'اکسیدهای نیتروژن' },
  PM: { limit: 50, unit: 'mg/Nm³', name: 'ذرات معلق' }
};

// سیستم تشخیص مشکل بر اساس آلاینده
const DIAGNOSTIC_SYSTEM = {
  CO: {
    high: 'احتراق ناقص - بررسی نسبت هوا به سوخت، تنظیم مشعل‌ها',
    veryHigh: 'نقص جدی در احتراق - بررسی فوری سیستم تهویه و مشعل‌ها'
  },
  CO2: {
    high: 'افزایش مصرف سوخت - بهینه‌سازی فرآیند احتراق',
    veryHigh: 'عدم کارایی سیستم - بررسی عایق‌بندی و تبادل حرارت'
  },
  SO2: {
    high: 'محتوای گوگرد بالا در سوخت - استفاده از سوخت با کیفیت بهتر',
    veryHigh: 'نیاز به سیستم دسولفوریزاسیون یا تعویض سوخت'
  },
  NOx: {
    high: 'دمای احتراق بالا - کاهش دما، استفاده از مشعل‌های NOx پایین',
    veryHigh: 'نیاز به سیستم SCR یا SNCR برای کاهش NOx'
  },
  PM: {
    high: 'احتراق ناکامل - بررسی سیستم فیلتراسیون و مشعل‌ها',
    veryHigh: 'نقص در سیستم فیلتر - تعویض یا تعمیر فیلترها'
  }
};

const EmissionMonitoringSystem = () => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [exhausts, setExhausts] = useState([
    { 
      id: 1, 
      name: 'اگزوز بویلر شماره 1', 
      data: { CO: 85, CO2: 420, SO2: 180, NOx: 140, PM: 45 },
      location: 'سالن تولید A',
      lastCheck: '1403/10/15'
    },
    { 
      id: 2, 
      name: 'اگزوز بویلر شماره 2', 
      data: { CO: 120, CO2: 550, SO2: 220, NOx: 180, PM: 65 },
      location: 'سالن تولید B',
      lastCheck: '1403/10/15'
    }
  ]);

  const [newData, setNewData] = useState({
    exhaustId: '',
    CO: '',
    CO2: '',
    SO2: '',
    NOx: '',
    PM: ''
  });

  const [aiAnalysis, setAiAnalysis] = useState(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);

  const calculateStatus = (value, limit) => {
    const percentage = (value / limit) * 100;
    if (percentage <= 80) return { status: 'خوب', color: '#10b981', level: 'safe' };
    if (percentage <= 100) return { status: 'قابل قبول', color: '#f59e0b', level: 'warning' };
    if (percentage <= 120) return { status: 'خطر', color: '#ef4444', level: 'danger' };
    return { status: 'بحرانی', color: '#dc2626', level: 'critical' };
  };

  const getExhaustOverallStatus = (exhaustData) => {
    let maxPercentage = 0;
    Object.keys(STANDARDS).forEach(pollutant => {
      const percentage = (exhaustData[pollutant] / STANDARDS[pollutant].limit) * 100;
      if (percentage > maxPercentage) maxPercentage = percentage;
    });
    return calculateStatus(maxPercentage * STANDARDS.CO.limit / 100, STANDARDS.CO.limit);
  };

  const handleAddData = () => {
    if (!newData.exhaustId) return;

    const exhaustIndex = exhausts.findIndex(e => e.id === parseInt(newData.exhaustId));
    if (exhaustIndex === -1) return;

    const updatedExhausts = [...exhausts];
    updatedExhausts[exhaustIndex].data = {
      CO: parseFloat(newData.CO) || 0,
      CO2: parseFloat(newData.CO2) || 0,
      SO2: parseFloat(newData.SO2) || 0,
      NOx: parseFloat(newData.NOx) || 0,
      PM: parseFloat(newData.PM) || 0
    };
    updatedExhausts[exhaustIndex].lastCheck = new Date().toLocaleDateString('fa-IR');

    setExhausts(updatedExhausts);
    setNewData({ exhaustId: '', CO: '', CO2: '', SO2: '', NOx: '', PM: '' });
  };

  const analyzeWithAI = async (exhaustData) => {
    setIsAnalyzing(true);
    try {
      const prompt = `تو یک متخصص زیست‌محیطی و مهندس بویلر هستی. داده‌های زیر مربوط به اندازه‌گیری آلاینده‌های خروجی یک بویلر صنعتی است:

${Object.entries(exhaustData.data).map(([pollutant, value]) => 
  `- ${STANDARDS[pollutant].name} (${pollutant}): ${value} ${STANDARDS[pollutant].unit} (استاندارد: ${STANDARDS[pollutant].limit})`
).join('\n')}

محل نصب: ${exhaustData.location}
آخرین بررسی: ${exhaustData.lastCheck}

لطفاً:
1. وضعیت کلی بویلر را تحلیل کن
2. مشکلات احتمالی را شناسایی کن
3. راهکارهای عملی برای بهبود وضعیت ارائه بده
4. اولویت‌بندی اقدامات را مشخص کن
5. تخمین زمان و هزینه تقریبی بده

پاسخ را به صورت ساختاریافته و فارسی ارائه بده.`;

      const response = await fetch("https://api.anthropic.com/v1/messages", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify({
          model: "claude-sonnet-4-20250514",
          max_tokens: 1000,
          messages: [
            { role: "user", content: prompt }
          ],
        })
      });

      const data = await response.json();
      const analysisText = data.content.find(c => c.type === 'text')?.text || 'خطا در دریافت تحلیل';

      setAiAnalysis({
        exhaustId: exhaustData.id,
        analysis: analysisText,
        timestamp: new Date().toLocaleString('fa-IR')
      });
    } catch (error) {
      setAiAnalysis({
        exhaustId: exhaustData.id,
        analysis: 'خطا در برقراری ارتباط با سیستم تحلیل هوش مصنوعی',
        timestamp: new Date().toLocaleString('fa-IR')
      });
    }
    setIsAnalyzing(false);
  };

  const getDetailedDiagnostic = (exhaustData) => {
    const diagnostics = [];
    Object.entries(exhaustData.data).forEach(([pollutant, value]) => {
      const limit = STANDARDS[pollutant].limit;
      const percentage = (value / limit) * 100;

      if (percentage > 100) {
        const severity = percentage > 120 ? 'veryHigh' : 'high';
        diagnostics.push({
          pollutant: STANDARDS[pollutant].name,
          value: value,
          limit: limit,
          percentage: percentage.toFixed(1),
          issue: DIAGNOSTIC_SYSTEM[pollutant][severity]
        });
      }
    });
    return diagnostics;
  };

  // داده برای نمودارهای مقایسه‌ای
  const getComparisonData = () => {
    return Object.keys(STANDARDS).map(pollutant => ({
      name: STANDARDS[pollutant].name,
      استاندارد: STANDARDS[pollutant].limit,
      ...exhausts.reduce((acc, exhaust) => {
        acc[exhaust.name] = exhaust.data[pollutant];
        return acc;
      }, {})
    }));
  };

  // داده برای نمودار رادار
  const getRadarData = (exhaustData) => {
    return Object.keys(STANDARDS).map(pollutant => ({
      pollutant: STANDARDS[pollutant].name,
      value: (exhaustData[pollutant] / STANDARDS[pollutant].limit) * 100,
      fullMark: 100
    }));
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-slate-900 via-slate-800 to-slate-900 text-white p-6" style={{direction: 'rtl'}}>
      <div className="max-w-7xl mx-auto">
        {/* هدر */}
        <div className="bg-gradient-to-r from-blue-600 to-blue-800 rounded-2xl p-6 mb-6 shadow-2xl">
          <h1 className="text-3xl font-bold mb-2">سامانه هوشمند پایش آلاینده‌های زیست‌محیطی</h1>
          <p className="text-blue-100">مطابق با استانداردهای ISO 14001</p>
        </div>

        {/* منوی تب‌ها */}
        <div className="flex gap-2 mb-6 bg-slate-800 p-2 rounded-xl">
          {[
            { id: 'dashboard', label: 'داشبورد', icon: Activity },
            { id: 'data-entry', label: 'ورود داده', icon: FileText },
            { id: 'analysis', label: 'تحلیل هوشمند', icon: TrendingUp }
          ].map(tab => (
            <button
              key={tab.id}
              onClick={() => setActiveTab(tab.id)}
              className={`flex-1 py-3 px-4 rounded-lg font-semibold transition-all flex items-center justify-center gap-2 ${
                activeTab === tab.id 
                  ? 'bg-blue-600 text-white shadow-lg' 
                  : 'bg-slate-700 text-gray-300 hover:bg-slate-600'
              }`}
            >
              <tab.icon size={20} />
              {tab.label}
            </button>
          ))}
        </div>

        {/* محتوای داشبورد */}
        {activeTab === 'dashboard' && (
          <div className="space-y-6">
            {/* کارت‌های وضعیت اگزوزها */}
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
              {exhausts.map(exhaust => {
                const overallStatus = getExhaustOverallStatus(exhaust.data);
                const diagnostics = getDetailedDiagnostic(exhaust);

                return (
                  <div key={exhaust.id} className="bg-slate-800 rounded-xl p-6 shadow-xl border border-slate-700">
                    <div className="flex justify-between items-start mb-4">
                      <div>
                        <h3 className="text-xl font-bold mb-1">{exhaust.name}</h3>
                        <p className="text-sm text-gray-400">{exhaust.location}</p>
                        <p className="text-xs text-gray-500 mt-1">آخرین بررسی: {exhaust.lastCheck}</p>
                      </div>
                      <div className={`px-4 py-2 rounded-full font-bold`} style={{backgroundColor: overallStatus.color}}>
                        {overallStatus.status}
                      </div>
                    </div>

                    {/* نمودار رادار */}
                    <div className="mb-4">
                      <ResponsiveContainer width="100%" height={200}>
                        <RadarChart data={getRadarData(exhaust.data)}>
                          <PolarGrid stroke="#475569" />
                          <PolarAngleAxis dataKey="pollutant" tick={{fill: '#94a3b8', fontSize: 11}} />
                          <PolarRadiusAxis angle={90} domain={[0, 150]} tick={{fill: '#64748b'}} />
                          <Radar name="درصد استاندارد" dataKey="value" stroke="#3b82f6" fill="#3b82f6" fillOpacity={0.6} />
                        </RadarChart>
                      </ResponsiveContainer>
                    </div>

                    {/* جدول آلاینده‌ها */}
                    <div className="space-y-2">
                      {Object.entries(exhaust.data).map(([pollutant, value]) => {
                        const limit = STANDARDS[pollutant].limit;
                        const status = calculateStatus(value, limit);
                        const percentage = ((value / limit) * 100).toFixed(1);

                        return (
                          <div key={pollutant} className="bg-slate-700 rounded-lg p-3">
                            <div className="flex justify-between items-center mb-2">
                              <span className="font-semibold">{STANDARDS[pollutant].name}</span>
                              <span className="text-sm" style={{color: status.color}}>{status.status}</span>
                            </div>
                            <div className="flex items-center gap-3">
                              <div className="flex-1">
                                <div className="h-2 bg-slate-600 rounded-full overflow-hidden">
                                  <div 
                                    className="h-full transition-all duration-500"
                                    style={{
                                      width: `${Math.min(percentage, 100)}%`,
                                      backgroundColor: status.color
                                    }}
                                  />
                                </div>
                              </div>
                              <span className="text-sm font-mono">
                                {value}/{limit} {STANDARDS[pollutant].unit}
                              </span>
                            </div>
                          </div>
                        );
                      })}
                    </div>

                    {/* هشدارها و تشخیص */}
                    {diagnostics.length > 0 && (
                      <div className="mt-4 bg-red-900/30 border border-red-700 rounded-lg p-4">
                        <h4 className="font-bold mb-2 flex items-center gap-2">
                          <AlertCircle size={18} />
                          مشکلات شناسایی شده:
                        </h4>
                        {diagnostics.map((diag, idx) => (
                          <div key={idx} className="text-sm mb-2 last:mb-0">
                            <strong>{diag.pollutant}</strong> ({diag.percentage}% از استاندارد):
                            <p className="text-gray-300 mt-1">{diag.issue}</p>
                          </div>
                        ))}
                      </div>
                    )}

                    <button
                      onClick={() => analyzeWithAI(exhaust)}
                      disabled={isAnalyzing}
                      className="w-full mt-4 bg-gradient-to-r from-purple-600 to-purple-700 hover:from-purple-700 hover:to-purple-800 py-3 rounded-lg font-semibold transition-all disabled:opacity-50"
                    >
                      {isAnalyzing ? 'در حال تحلیل...' : 'تحلیل هوشمند با AI'}
                    </button>
                  </div>
                );
              })}
            </div>

            {/* نمودار مقایسه‌ای */}
            <div className="bg-slate-800 rounded-xl p-6 shadow-xl border border-slate-700">
              <h3 className="text-xl font-bold mb-4">مقایسه آلاینده‌ها با استانداردهای ISO</h3>
              <ResponsiveContainer width="100%" height={400}>
                <BarChart data={getComparisonData()}>
                  <CartesianGrid strokeDasharray="3 3" stroke="#475569" />
                  <XAxis dataKey="name" tick={{fill: '#94a3b8'}} />
                  <YAxis tick={{fill: '#94a3b8'}} />
                  <Tooltip 
                    contentStyle={{backgroundColor: '#1e293b', border: '1px solid #475569', borderRadius: '8px'}}
                    labelStyle={{color: '#f1f5f9'}}
                  />
                  <Legend />
                  <Bar dataKey="استاندارد" fill="#10b981" />
                  {exhausts.map((exhaust, idx) => (
                    <Bar key={exhaust.id} dataKey={exhaust.name} fill={['#3b82f6', '#f59e0b', '#8b5cf6'][idx % 3]} />
                  ))}
                </BarChart>
              </ResponsiveContainer>
            </div>
          </div>
        )}

        {/* فرم ورود داده */}
        {activeTab === 'data-entry' && (
          <div className="bg-slate-800 rounded-xl p-6 shadow-xl border border-slate-700">
            <h2 className="text-2xl font-bold mb-6">ثبت داده‌های پایش فصلی</h2>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div>
                <label className="block mb-2 font-semibold">انتخاب اگزوز</label>
                <select
                  value={newData.exhaustId}
                  onChange={(e) => setNewData({...newData, exhaustId: e.target.value})}
                  className="w-full bg-slate-700 border border-slate-600 rounded-lg px-4 py-3 focus:outline-none focus:ring-2 focus:ring-blue-500"
                >
                  <option value="">انتخاب کنید...</option>
                  {exhausts.map(exhaust => (
                    <option key={exhaust.id} value={exhaust.id}>{exhaust.name}</option>
                  ))}
                </select>
              </div>

              {Object.keys(STANDARDS).map(pollutant => (
                <div key={pollutant}>
                  <label className="block mb-2 font-semibold">
                    {STANDARDS[pollutant].name} ({STANDARDS[pollutant].unit})
                  </label>
                  <input
                    type="number"
                    value={newData[pollutant]}
                    onChange={(e) => setNewData({...newData, [pollutant]: e.target.value})}
                    placeholder={`حداکثر: ${STANDARDS[pollutant].limit}`}
                    className="w-full bg-slate-700 border border-slate-600 rounded-lg px-4 py-3 focus:outline-none focus:ring-2 focus:ring-blue-500"
                  />
                </div>
              ))}
            </div>

            <button
              onClick={handleAddData}
              className="w-full mt-6 bg-gradient-to-r from-green-600 to-green-700 hover:from-green-700 hover:to-green-800 py-4 rounded-lg font-bold text-lg transition-all"
            >
              ثبت داده‌ها
            </button>
          </div>
        )}

        {/* نتایج تحلیل هوشمند */}
        {activeTab === 'analysis' && (
          <div className="bg-slate-800 rounded-xl p-6 shadow-xl border border-slate-700">
            <h2 className="text-2xl font-bold mb-6 flex items-center gap-3">
              <TrendingUp size={28} />
              تحلیل هوشمند با کمک AI
            </h2>

            {!aiAnalysis ? (
              <div className="text-center py-12 text-gray-400">
                <Activity size={48} className="mx-auto mb-4 opacity-50" />
                <p>برای دریافت تحلیل هوشمند، روی دکمه "تحلیل هوشمند با AI" در داشبورد کلیک کنید</p>
              </div>
            ) : (
              <div>
                <div className="bg-slate-700 rounded-lg p-4 mb-4">
                  <p className="text-sm text-gray-400">
                    تحلیل برای: {exhausts.find(e => e.id === aiAnalysis.exhaustId)?.name}
                  </p>
                  <p className="text-xs text-gray-500">زمان: {aiAnalysis.timestamp}</p>
                </div>

                <div className="bg-gradient-to-br from-purple-900/30 to-blue-900/30 border border-purple-700 rounded-lg p-6">
                  <pre className="whitespace-pre-wrap font-sans text-gray-200 leading-relaxed">
                    {aiAnalysis.analysis}
                  </pre>
                </div>
              </div>
            )}
          </div>
        )}
      </div>
    </div>
  );
};

export default EmissionMonitoringSystem;

