                </label>
                <div className="relative">
                  <input
                    type="number"
                    value={formData[pollutant] || ''}
                    onChange={(e) => setFormData({...formData, [pollutant]: parseFloat(e.target.value)})}
                    placeholder={`حداکثر: ${STANDARDS[pollutant].limit}`}
