          {activeTab === 'data-entry' && (
            <DataEntry 
              exhausts={exhausts} 
              onAddData={handleAddData} 
              onAddExhaust={handleAddExhaust}
            />
          )}

          {activeTab === 'analysis' && (
            <AnalysisResult 
              analysis={aiAnalysis}
              exhausts={exhausts}
              onBack={() => setActiveTab('dashboard')}
            />
          )}

          {activeTab === 'history' && (
            <HistoryLog logs={logs} />
          )}
        </main>
      </div>
    </div>
  );
};

