import React, { useState } from 'react';
import { FileText, Save, RefreshCcw, PlusCircle, Settings, Factory } from 'lucide-react';
import { Exhaust, PollutantData } from '../types';
import { STANDARDS } from '../constants';

interface DataEntryProps {
  exhausts: Exhaust[];
  onAddData: (exhaustId: string, data: PollutantData) => void;
  onAddExhaust: (name: string, location: string) => void;
}

export const DataEntry: React.FC<DataEntryProps> = ({ exhausts, onAddData, onAddExhaust }) => {
  const [mode, setMode] = useState<'entry' | 'create'>('entry');

  // State for Data Entry
  const [exhaustId, setExhaustId] = useState('');
  const [formData, setFormData] = useState<Partial<PollutantData>>({});

  // State for New Exhaust
  const [newExhaust, setNewExhaust] = useState({ name: '', location: '' });

  const handleSubmitData = () => {
    if (!exhaustId) return;

    const completeData: PollutantData = {
      CO: Number(formData.CO) || 0,
      CO2: Number(formData.CO2) || 0,
      SO2: Number(formData.SO2) || 0,
      NOx: Number(formData.NOx) || 0,
      PM: Number(formData.PM) || 0,
      O2: Number(formData.O2) || 0,
    };

    onAddData(exhaustId, completeData);
    setExhaustId('');
    setFormData({});
  };

  const handleCreateExhaust = () => {
    if (newExhaust.name && newExhaust.location) {
      onAddExhaust(newExhaust.name, newExhaust.location);
      setNewExhaust({ name: '', location: '' });
      setMode('entry'); // Switch back to entry mode so user can add data
    }
  };

  return (
    <div className="bg-slate-800/80 backdrop-blur-md rounded-2xl p-8 shadow-2xl border border-slate-700/50 max-w-4xl mx-auto animate-in slide-in-from-bottom-5 duration-500">

      {/* Tab Switcher */}
      <div className="flex bg-slate-900/50 p-1 rounded-xl mb-8 border border-slate-700">
        <button 
          onClick={() => setMode('entry')}
          className={`flex-1 py-3 rounded-lg font-bold text-sm md:text-base flex items-center justify-center gap-2 transition-all ${
            mode === 'entry' 
              ? 'bg-blue-600 text-white shadow-lg' 
              : 'text-slate-400 hover:text-white hover:bg-white/5'
          }`}
        >
          <FileText size={18} />
          ثبت داده‌های پایش
        </button>
        <button 
          onClick={() => setMode('create')}
          className={`flex-1 py-3 rounded-lg font-bold text-sm md:text-base flex items-center justify-center gap-2 transition-all ${
            mode === 'create' 
              ? 'bg-emerald-600 text-white shadow-lg' 
              : 'text-slate-400 hover:text-white hover:bg-white/5'
          }`}
        >
          <PlusCircle size={18} />
          تعریف اگزوز جدید
        </button>
      </div>

      {mode === 'entry' ? (
        <div className="animate-in fade-in slide-in-from-right-4 duration-300">
          <div className="flex items-center gap-3 mb-6 pb-4 border-b border-slate-700">
            <div className="p-3 bg-blue-500/20 rounded-xl text-blue-400">
              <Settings size={28} />
            </div>
            <div>
              <h2 className="text-2xl font-bold text-white">ورود مقادیر آلاینده‌ها</h2>
              <p className="text-slate-400 mt-1">انتخاب اگزوز و ثبت مقادیر اندازه‌گیری شده</p>
            </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
            <div className="md:col-span-2">
              <label className="block mb-2 text-sm font-semibold text-slate-300">منبع انتشار (اگزوز)</label>
              <select
                value={exhaustId}
                onChange={(e) => setExhaustId(e.target.value)}
                className="w-full bg-slate-900/50 border border-slate-600 rounded-xl px-4 py-3.5 text-white focus:outline-none focus:ring-2 focus:ring-blue-500 transition-all hover:bg-slate-900"
              >
                <option value="">انتخاب کنید...</option>
                {exhausts.map(exhaust => (
                  <option key={exhaust.id} value={exhaust.id}>{exhaust.name} - {exhaust.location}</option>
                ))}
              </select>
            </div>

            {Object.keys(STANDARDS).map(pollutant => (
              <div key={pollutant} className="group">
                <label className="flex justify-between mb-2 text-sm font-semibold text-slate-300">
                  <span>{STANDARDS[pollutant].name}</span>
                  <span className="text-slate-500 font-mono text-xs">{STANDARDS[pollutant].unit}</span>
                </label>
                <div className="relative">
                  <input
                    type="number"
                    value={formData[pollutant] || ''}
                    onChange={(e) => setFormData({...formData, [pollutant]: parseFloat(e.target.value)})}
                    placeholder={`حداکثر: ${STANDARDS[pollutant].limit}`}
                    className="w-full bg-slate-900/50 border border-slate-600 rounded-xl px-4 py-3.5 text-white focus:outline-none focus:ring-2 focus:ring-blue-500 transition-all hover:bg-slate-900"
                  />
                  <div className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-600 text-xs font-mono">
                    {pollutant}
                  </div>
                </div>
                <div className="h-1 bg-slate-700 mt-2 rounded-full overflow-hidden opacity-0 group-focus-within:opacity-100 transition-opacity">
                   <div 
                     className={`h-full ${Number(formData[pollutant] || 0) > STANDARDS[pollutant].limit ? 'bg-red-500' : 'bg-green-500'}`} 
                     style={{width: '100%'}}
                   />
                </div>
              </div>
            ))}
          </div>

          <div className="flex gap-4 mt-8 pt-6 border-t border-slate-700">
            <button
                onClick={() => {setExhaustId(''); setFormData({});}}
                className="flex-1 bg-slate-700 hover:bg-slate-600 text-slate-200 py-4 rounded-xl font-bold transition-all flex items-center justify-center gap-2"
            >
              <RefreshCcw size={20} />
              پاک کردن
            </button>
            <button
              onClick={handleSubmitData}
              className="flex-[2] bg-gradient-to-r from-blue-600 to-indigo-600 hover:from-blue-500 hover:to-indigo-500 text-white py-4 rounded-xl font-bold shadow-lg shadow-blue-500/20 transition-all active:scale-[0.98] flex items-center justify-center gap-2"
            >
              <Save size={20} />
              ذخیره اطلاعات
            </button>
          </div>
        </div>
      ) : (
        <div className="animate-in fade-in slide-in-from-left-4 duration-300">
          <div className="flex items-center gap-3 mb-6 pb-4 border-b border-slate-700">
            <div className="p-3 bg-emerald-500/20 rounded-xl text-emerald-400">
              <Factory size={28} />
            </div>
            <div>
              <h2 className="text-2xl font-bold text-white">افزودن اگزوز جدید</h2>
              <p className="text-slate-400 mt-1">تعریف یک نقطه پایش جدید در سامانه</p>
            </div>
          </div>

          <div className="space-y-6">
            <div>
              <label className="block mb-2 text-sm font-semibold text-slate-300">نام اگزوز یا تجهیز</label>
              <input
                type="text"
                value={newExhaust.name}
                onChange={(e) => setNewExhaust({...newExhaust, name: e.target.value})}
                placeholder="مثال: بویلر شماره ۳"
                className="w-full bg-slate-900/50 border border-slate-600 rounded-xl px-4 py-3.5 text-white focus:outline-none focus:ring-2 focus:ring-emerald-500 transition-all hover:bg-slate-900"
              />
            </div>

            <div>
              <label className="block mb-2 text-sm font-semibold text-slate-300">موقعیت مکانی</label>
              <input
                type="text"
                value={newExhaust.location}
                onChange={(e) => setNewExhaust({...newExhaust, location: e.target.value})}
                placeholder="مثال: سالن تولید C - ضلع شمالی"
                className="w-full bg-slate-900/50 border border-slate-600 rounded-xl px-4 py-3.5 text-white focus:outline-none focus:ring-2 focus:ring-emerald-500 transition-all hover:bg-slate-900"
              />
            </div>
          </div>

          <div className="flex gap-4 mt-8 pt-6 border-t border-slate-700">
            <button
              onClick={() => setNewExhaust({ name: '', location: '' })}
              className="flex-1 bg-slate-700 hover:bg-slate-600 text-slate-200 py-4 rounded-xl font-bold transition-all flex items-center justify-center gap-2"
            >
              <RefreshCcw size={20} />
              انصراف
            </button>
            <button
              onClick={handleCreateExhaust}
              disabled={!newExhaust.name || !newExhaust.location}
              className="flex-[2] bg-gradient-to-r from-emerald-600 to-green-600 hover:from-emerald-500 hover:to-green-500 disabled:opacity-50 disabled:cursor-not-allowed text-white py-4 rounded-xl font-bold shadow-lg shadow-emerald-500/20 transition-all active:scale-[0.98] flex items-center justify-center gap-2"
            >
              <PlusCircle size={20} />
              ایجاد اگزوز جدید
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

import React, { useState } from 'react';
import { Activity, FileText, TrendingUp, Menu, Zap, History } from 'lucide-react';
import { Dashboard } from './components/Dashboard';
import { DataEntry } from './components/DataEntry';
import { AnalysisResult } from './components/AnalysisResult';
import { HistoryLog } from './components/HistoryLog';
import { Exhaust, PollutantData, AIAnalysisResult, TabType, HistoryLogEntry } from './types';
import { INITIAL_EXHAUSTS } from './constants';
import { generateExhaustAnalysis } from './services/geminiService';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<TabType>('dashboard');
  const [exhausts, setExhausts] = useState<Exhaust[]>(INITIAL_EXHAUSTS);
  const [aiAnalysis, setAiAnalysis] = useState<AIAnalysisResult | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);

  // History Logs State
  const [logs, setLogs] = useState<HistoryLogEntry[]>([
    {
      id: 'init',
      action: 'system',
      title: 'راه‌اندازی سیستم',
      description: 'سامانه با داده‌های اولیه بارگذاری شد.',
      timestamp: new Date().toLocaleString('fa-IR')
    }
  ]);

  const addLog = (action: HistoryLogEntry['action'], title: string, description: string, exhaustName?: string) => {
    const newLog: HistoryLogEntry = {
      id: Date.now().toString(),
      action,
      title,
      description,
      timestamp: new Date().toLocaleString('fa-IR'),
      exhaustName
    };
    setLogs(prev => [newLog, ...prev]);
  };

  const handleAddData = (exhaustId: string, newData: PollutantData) => {
    let exhaustName = '';
    setExhausts(prev => prev.map(exhaust => {
      if (exhaust.id === parseInt(exhaustId)) {
        exhaustName = exhaust.name;
        return {
          ...exhaust,
          data: newData,
          lastCheck: new Date().toLocaleDateString('fa-IR')
        };
      }
      return exhaust;
    }));

    addLog(
      'data_entry',
      'بروزرسانی داده‌های پایش',
      'مقادیر جدید آلاینده‌ها توسط اپراتور ثبت و ذخیره شد.',
      exhaustName
    );
    setActiveTab('dashboard');
  };

  const handleAddExhaust = (name: string, location: string) => {
    const newId = exhausts.length > 0 ? Math.max(...exhausts.map(e => e.id)) + 1 : 1;
    const newExhaust: Exhaust = {
      id: newId,
      name,
      location,
      data: { CO: 0, CO2: 0, SO2: 0, NOx: 0, PM: 0, O2: 0 },
      lastCheck: 'ثبت نشده'
    };
    setExhausts(prev => [...prev, newExhaust]);

    addLog(
      'new_exhaust',
      'افزودن منبع جدید',
      `اگزوز جدید با موقعیت مکانی "${location}" به سامانه اضافه شد.`,
      name
    );
  };

  const handleAnalyze = async (exhaust: Exhaust) => {
    setIsAnalyzing(true);
    try {
      const resultText = await generateExhaustAnalysis(exhaust);
      setAiAnalysis({
        exhaustId: exhaust.id,
        analysis: resultText,
        timestamp: new Date().toLocaleString('fa-IR')
      });

      addLog(
        'ai_analysis',
        'تحلیل هوشمند موفق',
        'گزارش فنی و تحلیل آلاینده‌ها توسط هوش مصنوعی تولید شد.',
        exhaust.name
      );

      setActiveTab('analysis');
    } catch (error) {
      console.error("Analysis failed", error);
    } finally {
      setIsAnalyzing(false);
    }
  };

  const navItems = [
    { id: 'dashboard', label: 'داشبورد وضعیت', icon: Activity },
    { id: 'data-entry', label: 'مدیریت داده‌ها', icon: FileText },
    { id: 'analysis', label: 'تحلیل هوشمند', icon: TrendingUp },
    { id: 'history', label: 'تاریخچه فعالیت', icon: History }
  ];

  return (
    <div className="min-h-screen bg-[radial-gradient(ellipse_at_top,_var(--tw-gradient-stops))] from-slate-900 via-slate-900 to-black text-white selection:bg-blue-500 selection:text-white" dir="rtl">
      <div className="max-w-7xl mx-auto p-4 md:p-6 lg:p-8">

        {/* Header */}
        <header className="mb-10 animate-in slide-in-from-top-5 duration-700">
          <div className="bg-gradient-to-r from-blue-700 to-indigo-800 rounded-3xl p-8 shadow-2xl shadow-blue-900/20 border border-blue-600/30 relative overflow-hidden">
             {/* Background Pattern */}
            <div className="absolute top-0 left-0 w-full h-full opacity-10">
                <svg className="w-full h-full" viewBox="0 0 100 100" preserveAspectRatio="none">
                    <path d="M0 100 C 20 0 50 0 100 100 Z" fill="white" />
                </svg>
            </div>

            <div className="relative z-10 flex flex-col md:flex-row justify-between items-center gap-6">
              <div>
                <h1 className="text-3xl md:text-4xl font-black mb-2 tracking-tight">
                  سامانه هوشمند <span className="text-transparent bg-clip-text bg-gradient-to-r from-cyan-300 to-blue-300">EcoMonitor</span>
                </h1>
                <p className="text-blue-100/80 font-medium text-lg max-w-2xl">
                  پایش لحظه‌ای آلاینده‌های صنعتی منطبق با استانداردهای ISO 14001 با بهره‌گیری از هوش مصنوعی مولد
                </p>
              </div>
              <div className="hidden md:flex items-center gap-3 bg-white/10 backdrop-blur-md px-4 py-2 rounded-xl border border-white/10">
                 <Zap className="text-yellow-400 fill-yellow-400" />
                 <span className="font-bold">Gemini 3 Powered</span>
              </div>
            </div>
          </div>
        </header>

        {/* Navigation */}
        <nav className="flex flex-col sm:flex-row gap-3 mb-8 bg-slate-900/50 p-2 rounded-2xl border border-slate-800 backdrop-blur-sm sticky top-4 z-50 shadow-xl overflow-x-auto">
          {navItems.map(tab => (
            <button
              key={tab.id}
              onClick={() => setActiveTab(tab.id as TabType)}
              className={`flex-1 min-w-[140px] py-4 px-6 rounded-xl font-bold transition-all duration-300 flex items-center justify-center gap-3 text-sm md:text-base ${
                activeTab === tab.id 
                  ? 'bg-blue-600 text-white shadow-lg shadow-blue-600/30 scale-[1.02]' 
                  : 'bg-transparent text-slate-400 hover:bg-slate-800 hover:text-slate-200'
              }`}
            >
              <tab.icon size={22} strokeWidth={2.5} />
              {tab.label}
            </button>
          ))}
        </nav>

        {/* Main Content Area */}
        <main className="min-h-[500px]">
          {activeTab === 'dashboard' && (
            <Dashboard 
              exhausts={exhausts} 
              onAnalyze={handleAnalyze} 
              isAnalyzing={isAnalyzing} 
            />
          )}

          {activeTab === 'data-entry' && (
            <DataEntry 
              exhausts={exhausts} 
              onAddData={handleAddData} 
              onAddExhaust={handleAddExhaust}
            />
          )}

          {activeTab === 'analysis' && (
            <AnalysisResult 
              analysis={aiAnalysis}
              exhausts={exhausts} 
              onBack={() => setActiveTab('dashboard')}
            />
          )}

          {activeTab === 'history' && (
            <HistoryLog logs={logs} />
          )}
        </main>
      </div>
    </div>
  );
};

export default App;

