          </div>
        </div>
      );
    }

    return this.props.children;
  }
}

import React, { useState, useEffect } from 'react';
import { Activity, FileText, TrendingUp, Zap, BarChart3, Info, Moon, Sun, Palette, MessageSquare, Wifi, WifiOff } from 'lucide-react';
import { Dashboard } from './components/Dashboard';
import { DataEntry } from './components/DataEntry';
import { AnalysisResult } from './components/AnalysisResult';
import { MeasurementHistory } from './components/HistoryLog';
import { ExhaustDetails } from './components/ExhaustDetails';
import { ChatBot } from './components/ChatBot';
import { Exhaust, PollutantData, AIAnalysisResult, TabType } from './types';
import { INITIAL_EXHAUSTS } from './constants';
import { generateExhaustAnalysis } from './services/geminiService';
import { useSettings, AccentColor } from './contexts/SettingsContext';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<TabType | 'chat'>('dashboard');

  // Initialize state from LocalStorage or fallback to constants
  const [exhausts, setExhausts] = useState<Exhaust[]>(() => {
    try {
      const saved = localStorage.getItem('ecomonitor_exhausts');
      return saved ? JSON.parse(saved) : INITIAL_EXHAUSTS;
    } catch (e) {
      console.error("Failed to load from local storage", e);
      return INITIAL_EXHAUSTS;
    }
  });

  const [aiAnalysis, setAiAnalysis] = useState<AIAnalysisResult | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [isOnline, setIsOnline] = useState(navigator.onLine);

  // Navigation visual state
  const [isScrolled, setIsScrolled] = useState(false);

  const { theme, toggleTheme, language, toggleLanguage, t, dir, accentColor, setAccentColor, themeColors } = useSettings();

  // Persist data when changed
  useEffect(() => {
    localStorage.setItem('ecomonitor_exhausts', JSON.stringify(exhausts));
  }, [exhausts]);

  // Monitor Network Status
  useEffect(() => {
    const handleOnline = () => setIsOnline(true);
    const handleOffline = () => setIsOnline(false);

    window.addEventListener('online', handleOnline);
    window.addEventListener('offline', handleOffline);

    return () => {
      window.removeEventListener('online', handleOnline);
      window.removeEventListener('offline', handleOffline);
    };
  }, []);

  // Handle Scroll Effect
  useEffect(() => {
    const handleScroll = () => {
      setIsScrolled(window.scrollY > 20);
    };

    window.addEventListener('scroll', handleScroll, { passive: true });
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const handleAddData = (exhaustId: string, newData: PollutantData, period: string) => {
    const timestamp = new Date().toLocaleDateString(language === 'fa' ? 'fa-IR' : 'en-US');

    setExhausts(prev => prev.map(exhaust => {
      if (exhaust.id === parseInt(exhaustId)) {
        return {
          ...exhaust,
          data: newData,
          lastCheck: timestamp,
          history: [
            ...exhaust.history, 
            {
                period: period,
                date: timestamp,
                data: newData
            }
          ]
        };
      }
      return exhaust;
    }));
    setActiveTab('details');
  };

  const handleAddExhaust = (name: string, location: string) => {
    const newId = exhausts.length > 0 ? Math.max(...exhausts.map(e => e.id)) + 1 : 1;
    const newExhaust: Exhaust = {
      id: newId,
      name,
      location,
      data: { CO: 0, CO2: 0, SO2: 0, NOx: 0, PM: 0, O2: 0 },
      history: [],
      lastCheck: 'ثبت نشده'
    };
    setExhausts(prev => [...prev, newExhaust]);
  };

  const handleImportData = (data: Exhaust[]) => {
      setExhausts(data);
  };

  const handleAnalyze = async (exhaust: Exhaust, switchTab: boolean = true) => {
    if (!isOnline) {
      alert(t('error.offlineDesc'));
      return;
    }

    setIsAnalyzing(true);
    try {
      const resultText = await generateExhaustAnalysis(exhaust);
      setAiAnalysis({
        exhaustId: exhaust.id,
        analysis: resultText,
        timestamp: new Date().toLocaleString(language === 'fa' ? 'fa-IR' : 'en-US')
      });
      if (switchTab) setActiveTab('analysis');
    } catch (error) {
      console.error("Analysis failed", error);
    } finally {
      setIsAnalyzing(false);
    }
  };

  const navItems = [
    { id: 'dashboard', label: t('nav.dashboard'), icon: Activity },
    { id: 'details', label: t('nav.details'), icon: Info },
    { id: 'data-entry', label: t('nav.dataEntry'), icon: FileText },
    { id: 'analysis', label: t('nav.analysis'), icon: TrendingUp },
    { id: 'chat', label: t('nav.chat'), icon: MessageSquare },
    { id: 'history', label: t('nav.history'), icon: BarChart3 }
  ];

  const colors: { id: AccentColor; bg: string }[] = [
    { id: 'blue', bg: 'bg-blue-600' },
    { id: 'emerald', bg: 'bg-emerald-600' },
    { id: 'violet', bg: 'bg-violet-600' },
    { id: 'amber', bg: 'bg-amber-600' },
    { id: 'rose', bg: 'bg-rose-600' },
  ];

  return (
    <div 
      className="min-h-screen bg-gray-50 dark:bg-[radial-gradient(ellipse_at_top,_var(--tw-gradient-stops))] dark:from-slate-900 dark:via-slate-900 dark:to-black text-slate-900 dark:text-white transition-colors duration-300" 
      dir={dir}
      style={{
        '--theme-primary': themeColors.primary,
        '--theme-hover': themeColors.hover,
        '--theme-light': themeColors.light,
        '--theme-text': themeColors.text,
      } as React.CSSProperties}
    >
      <div className="max-w-7xl mx-auto p-3 md:p-6 lg:p-8 pb-20 md:pb-8">

        {/* Header */}
        <header className="mb-6 md:mb-10 animate-in slide-in-from-top-5 duration-700">
          <div className="bg-white dark:bg-slate-800 rounded-3xl p-5 md:p-8 shadow-xl dark:shadow-slate-900/20 border border-gray-200 dark:border-slate-700 relative overflow-hidden transition-all duration-300">
             {/* Gradient Background based on Theme */}
             <div 
               className="absolute top-0 right-0 w-full h-full opacity-0 dark:opacity-20 pointer-events-none transition-colors duration-500"
               style={{ background: `linear-gradient(to right, ${themeColors.primary}, transparent)` }}
             />

            <div className="relative z-10 flex flex-col lg:flex-row justify-between items-center gap-6">
              <div className="text-center lg:text-right">
                <h1 className="text-2xl md:text-3xl lg:text-4xl font-black mb-2 tracking-tight">
                  {t('app.title')} <span className="text-transparent bg-clip-text" style={{ backgroundImage: `linear-gradient(to right, ${themeColors.primary}, ${themeColors.hover})` }}>EcoMonitor</span>
                </h1>
                <p className="text-slate-600 dark:text-slate-400 font-medium text-sm md:text-lg max-w-2xl">
                  {t('app.subtitle')}
                </p>
              </div>

              <div className="flex flex-col sm:flex-row items-center gap-4 w-full sm:w-auto">

                {/* Online Status Indicator */}
                <div 
                  className={`flex items-center justify-center gap-2 px-3 py-2 rounded-xl border text-xs md:text-sm font-bold transition-all w-full sm:w-auto ${
                    isOnline 
                      ? 'bg-emerald-50 dark:bg-emerald-900/20 border-emerald-200 dark:border-emerald-800 text-emerald-600 dark:text-emerald-400' 
                      : 'bg-red-50 dark:bg-red-900/20 border-red-200 dark:border-red-800 text-red-600 dark:text-red-400'
                  }`}
                  title={isOnline ? t('status.online') : t('status.offline')}
                >
                  {isOnline ? <Wifi size={16} /> : <WifiOff size={16} />}
                  <span>{isOnline ? t('status.online') : t('status.offline')}</span>
                </div>

                <div className="flex w-full sm:w-auto justify-center gap-2">
                    {/* Color Picker */}
                    <div className="flex items-center gap-1.5 p-2 bg-gray-100 dark:bg-slate-900/50 rounded-xl border border-gray-200 dark:border-slate-700">
                        <Palette size={16} className="text-slate-500 ml-1 hidden sm:block" />
                        {colors.map(c => (
                            <button
                                key={c.id}
                                onClick={() => setAccentColor(c.id)}
                                className={`w-5 h-5 md:w-6 md:h-6 rounded-full transition-transform hover:scale-110 ${c.bg} ${accentColor === c.id ? 'ring-2 ring-offset-2 ring-slate-400 dark:ring-white scale-110' : 'opacity-70 hover:opacity-100'}`}
                            />
                        ))}
                    </div>

                    <div className="flex items-center gap-2">
                        <button 
                            onClick={toggleTheme}
                            className="p-2.5 md:p-3 rounded-xl bg-gray-100 dark:bg-white/10 text-slate-700 dark:text-white border border-gray-200 dark:border-white/10 hover:bg-gray-200 dark:hover:bg-white/20 transition-all"
                        >
                            {theme === 'dark' ? <Sun size={18} /> : <Moon size={18} />}
                        </button>
                        <button 
                            onClick={toggleLanguage}
                            className="p-2.5 md:p-3 rounded-xl bg-gray-100 dark:bg-white/10 text-slate-700 dark:text-white border border-gray-200 dark:border-white/10 hover:bg-gray-200 dark:hover:bg-white/20 transition-all font-bold w-12 text-sm"
                        >
                            {language === 'fa' ? 'En' : 'فا'}
                        </button>
                    </div>
                </div>

                <div className="hidden xl:flex items-center gap-3 bg-blue-50 dark:bg-white/10 backdrop-blur-md px-4 py-2.5 rounded-xl border border-blue-100 dark:border-white/10">
                    <Zap className="text-amber-500 dark:text-yellow-400 fill-amber-500 dark:fill-yellow-400" />
                    <span className="font-bold text-slate-800 dark:text-white text-sm">{t('gemini.powered')}</span>
                </div>
              </div>
            </div>
          </div>
        </header>

        {/* Navigation - Always visible sticky dock with compact effect on scroll */}
        <nav 
          className={`
            flex flex-row items-center gap-2 mb-6 
            backdrop-blur-xl sticky top-2 z-50 
            overflow-x-auto custom-scrollbar scroll-smooth
            transition-all duration-500 cubic-bezier(0.4, 0, 0.2, 1)
            border
            ${isScrolled 
              ? 'bg-white/95 dark:bg-slate-800/95 shadow-2xl border-gray-300 dark:border-slate-600 p-1.5 md:p-2 rounded-2xl md:rounded-[2rem] mx-0 md:mx-auto md:max-w-4xl' 
              : 'bg-white/60 dark:bg-slate-900/50 shadow-lg border-gray-200 dark:border-slate-800 p-2 md:p-3 rounded-2xl w-full'}
          `}
        >
          {navItems.map(tab => (
            <button
              key={tab.id}
              onClick={() => setActiveTab(tab.id as any)}
              className={`
                flex-1 min-w-[auto] md:min-w-[120px] rounded-xl font-bold transition-all duration-300 flex items-center justify-center gap-2 whitespace-nowrap
                ${isScrolled ? 'py-2.5 px-3 text-xs md:text-sm' : 'py-3 px-4 md:py-4 md:px-6 text-xs md:text-base'}
                ${activeTab === tab.id 
                  ? 'text-white shadow-md scale-[1.02]' 
                  : 'bg-transparent text-slate-500 dark:text-slate-400 hover:bg-gray-100/50 dark:hover:bg-slate-700/50 hover:text-slate-900 dark:hover:text-slate-200'}
              `}
              style={activeTab === tab.id ? { backgroundColor: themeColors.primary, boxShadow: `0 4px 12px ${themeColors.primary}40` } : {}}
            >
              <tab.icon size={isScrolled ? 16 : 20} strokeWidth={2.5} className="transition-all duration-300 shrink-0" />
              <span className={isScrolled ? 'hidden sm:inline' : 'inline'}>{tab.label}</span>
            </button>
          ))}
        </nav>

        {/* Main Content Area */}
        <main className="min-h-[500px]">
          {activeTab === 'dashboard' && (
            <Dashboard 
              exhausts={exhausts} 
              onAnalyze={(e) => handleAnalyze(e, true)} 
              isAnalyzing={isAnalyzing} 
              isOnline={isOnline}
            />
          )}

          {activeTab === 'details' && (
            <ExhaustDetails 
              exhausts={exhausts}
              aiAnalysis={aiAnalysis}
              isAnalyzing={isAnalyzing}
              onAnalyze={handleAnalyze}
              isOnline={isOnline}
            />
          )}

          {activeTab === 'data-entry' && (
            <DataEntry 
              exhausts={exhausts} 
              onAddData={handleAddData} 
              onAddExhaust={handleAddExhaust}
              onImportData={handleImportData}
            />
          )}

          {activeTab === 'analysis' && (
            <AnalysisResult 
              analysis={aiAnalysis}
              exhausts={exhausts} 
              onBack={() => setActiveTab('dashboard')}
            />
          )}

          {activeTab === 'chat' && (
             <ChatBot isOnline={isOnline} />
          )}

          {activeTab === 'history' && (
            <MeasurementHistory exhausts={exhausts} />
          )}
        </main>
      </div>
    </div>
  );
};

export default App;

import React from 'react';
import { 
  BarChart, Bar, Cell, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer, 
  RadarChart, PolarGrid, PolarAngleAxis, PolarRadiusAxis, Radar 
} from 'recharts';
import { AlertCircle, Activity, WifiOff } from 'lucide-react';
import { Exhaust } from '../types';
import { STANDARDS, DIAGNOSTIC_SYSTEM } from '../constants';
import { useSettings } from '../contexts/SettingsContext';

interface DashboardProps {
  exhausts: Exhaust[];
  onAnalyze: (exhaust: Exhaust) => void;
  isAnalyzing: boolean;
  isOnline: boolean;
}

export const Dashboard: React.FC<DashboardProps> = ({ exhausts, onAnalyze, isAnalyzing, isOnline }) => {
  const { themeColors, t } = useSettings();

  const calculateStatus = (value: number, limit: number) => {
    const percentage = (value / limit) * 100;
    if (percentage <= 80) return { status: 'خوب', color: '#10b981', level: 'safe' };
    if (percentage <= 100) return { status: 'قابل قبول', color: '#f59e0b', level: 'warning' };
    if (percentage <= 120) return { status: 'خطر', color: '#ef4444', level: 'danger' };
    return { status: 'بحرانی', color: '#dc2626', level: 'critical' };
  };

  const getExhaustOverallStatus = (exhaustData: any) => {
    let maxPercentage = 0;
    Object.keys(STANDARDS).forEach(pollutant => {
      const percentage = (exhaustData[pollutant] / STANDARDS[pollutant].limit) * 100;
      if (percentage > maxPercentage) maxPercentage = percentage;
    });
    return calculateStatus(maxPercentage * STANDARDS.CO.limit / 100, STANDARDS.CO.limit);
  };

  const getDetailedDiagnostic = (exhaustData: Exhaust) => {
    const diagnostics: any[] = [];
    Object.entries(exhaustData.data).forEach(([pollutant, value]) => {
      const limit = STANDARDS[pollutant].limit;
      const percentage = ((value as number) / limit) * 100;

      if (percentage > 100) {
        const severity = percentage > 120 ? 'veryHigh' : 'high';
        diagnostics.push({
          pollutant: STANDARDS[pollutant].name,
          value: value,
          limit: limit,
          percentage: percentage.toFixed(1),
          issue: DIAGNOSTIC_SYSTEM[pollutant][severity as 'high' | 'veryHigh']
        });
      }
    });
    return diagnostics;
  };

  const getRadarData = (exhaustData: any) => {
    return Object.keys(STANDARDS).map(pollutant => ({
      pollutant: STANDARDS[pollutant].name,
      value: (exhaustData[pollutant] / STANDARDS[pollutant].limit) * 100,
      fullMark: 100
    }));
  };

  const comparisonData = Object.keys(STANDARDS).map(pollutant => ({
    name: STANDARDS[pollutant].name,
    استاندارد: STANDARDS[pollutant].limit,
    ...exhausts.reduce((acc: any, exhaust) => {
      acc[exhaust.name] = exhaust.data[pollutant];
      return acc;
    }, {})
  }));

  return (
    <div className="w-full space-y-6 animate-in fade-in duration-500">
      <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-2 gap-4 md:gap-6">
        {exhausts.map(exhaust => {
          const overallStatus = getExhaustOverallStatus(exhaust.data);
          const diagnostics = getDetailedDiagnostic(exhaust);

          return (
            <div key={exhaust.id} className="bg-white dark:bg-slate-800/80 backdrop-blur-md rounded-2xl p-4 md:p-6 shadow-xl border border-gray-200 dark:border-slate-700/50 hover:border-gray-300 dark:hover:border-slate-600 transition-all min-w-0">
              <div className="flex flex-wrap justify-between items-start mb-4 gap-2">
                <div>
                  <h3 className="text-lg md:text-xl font-bold mb-1 text-slate-800 dark:text-white truncate max-w-[200px] md:max-w-none">{exhaust.name}</h3>
                  <p className="text-xs md:text-sm text-slate-500 dark:text-slate-400">{exhaust.location}</p>
                  <p className="text-[10px] md:text-xs text-slate-400 dark:text-slate-500 mt-1">آخرین بررسی: {exhaust.lastCheck}</p>
                </div>
                <div className={`px-3 py-1.5 md:px-4 md:py-2 rounded-full font-bold text-xs md:text-sm text-white shadow-lg whitespace-nowrap`} style={{backgroundColor: overallStatus.color}}>
                  {overallStatus.status}
                </div>
              </div>

              <div className="mb-6 h-[200px] sm:h-[220px] w-full" dir="ltr">
                <ResponsiveContainer width="99%" height="100%">
                  <RadarChart cx="50%" cy="50%" outerRadius="70%" data={getRadarData(exhaust.data)}>
                    <PolarGrid stroke="#94a3b8" strokeDasharray="3 3" />
                    <PolarAngleAxis dataKey="pollutant" tick={{fill: '#64748b', fontSize: 10}} />
                    <PolarRadiusAxis angle={90} domain={[0, 150]} tick={{fill: '#64748b', fontSize: 10}} />
                    <Radar name="درصد استاندارد" dataKey="value" stroke={themeColors.primary} fill={themeColors.primary} fillOpacity={0.5} />
                  </RadarChart>
                </ResponsiveContainer>
              </div>

              <div className="space-y-2 md:space-y-3">
                {Object.entries(exhaust.data).map(([pollutant, value]) => {
                  const limit = STANDARDS[pollutant].limit;
                  const val = value as number;
                  const status = calculateStatus(val, limit);
                  const percentage = ((val / limit) * 100).toFixed(1);

                  return (
                    <div key={pollutant} className="bg-gray-50 dark:bg-slate-700/50 rounded-lg p-2 md:p-3 border border-gray-100 dark:border-slate-600/30">
                      <div className="flex justify-between items-center mb-2">
                        <span className="text-xs md:text-sm font-semibold text-slate-700 dark:text-slate-200">{STANDARDS[pollutant].name}</span>
                        <span className="text-xs md:text-sm font-medium" style={{color: status.color}}>{status.status}</span>
                      </div>
                      <div className="flex items-center gap-2 md:gap-3">
                        <div className="flex-1 bg-gray-200 dark:bg-slate-900 rounded-full h-2 md:h-2.5">
                          <div 
                            className="h-full rounded-full transition-all duration-1000 ease-out"
                            style={{
                              width: `${Math.min(parseFloat(percentage), 100)}%`,
                              backgroundColor: status.color
                            }}
                          />
                        </div>
                        <span className="text-[10px] md:text-xs font-mono text-slate-500 dark:text-slate-400 min-w-[60px] md:min-w-[80px] text-left" dir="ltr">
                          {val} / {limit}
                        </span>
                      </div>
                    </div>
                  );
                })}
              </div>

              {diagnostics.length > 0 && (
                <div className="mt-4 bg-red-50 dark:bg-red-950/40 border border-red-200 dark:border-red-500/30 rounded-xl p-3 md:p-4">
                  <h4 className="font-bold mb-2 flex items-center gap-2 text-sm md:text-base text-red-600 dark:text-red-400">
                    <AlertCircle size={16} />
                    هشدار سیستم:
                  </h4>
                  {diagnostics.map((diag, idx) => (
                    <div key={idx} className="text-xs md:text-sm mb-2 last:mb-0 text-slate-600 dark:text-slate-300">
                      <strong className="text-red-500 dark:text-red-300">{diag.pollutant}</strong> ({diag.percentage}%):
                      <p className="mt-1 opacity-80">{diag.issue}</p>
                    </div>
                  ))}
                </div>
              )}

              <button
                onClick={() => onAnalyze(exhaust)}
                disabled={isAnalyzing || !isOnline}
                title={!isOnline ? t('error.offlineDesc') : ''}
                className="group w-full mt-6 py-3 rounded-xl font-bold text-sm md:text-base text-white shadow-lg transition-all active:scale-[0.98] disabled:opacity-50 disabled:cursor-not-allowed flex items-center justify-center gap-2"
                style={isOnline 
                  ? { backgroundImage: `linear-gradient(to right, ${themeColors.primary}, ${themeColors.hover})`, boxShadow: `0 10px 15px -3px ${themeColors.primary}30` } 
                  : { backgroundColor: '#94a3b8' }
                }
              >
                {!isOnline ? (
                  <>
                    <WifiOff size={18} />
                    {t('error.offline')}
                  </>
                ) : isAnalyzing ? (
                  <>
                    <Activity className="animate-spin" size={18} />
                    در حال تحلیل...
                  </>
                ) : (
                  <>
                    <Activity size={18} className="group-hover:scale-110 transition-transform" />
                    تحلیل پیشرفته با AI
                  </>
                )}
              </button>
            </div>
          );
        })}
      </div>

      <div className="bg-white dark:bg-slate-800/80 backdrop-blur-md rounded-2xl p-4 md:p-6 shadow-xl border border-gray-200 dark:border-slate-700/50 w-full min-w-0">
        <h3 className="text-lg md:text-xl font-bold mb-4 md:mb-6 text-slate-800 dark:text-white flex items-center gap-2">
          <Activity className="text-green-500" size={24} />
          <span className="text-sm md:text-lg">مقایسه جامع آلاینده‌ها با استانداردهای ISO 14001</span>
        </h3>
        <div className="h-[300px] md:h-[400px] w-full" dir="ltr">
          <ResponsiveContainer width="99%" height="100%">
            <BarChart data={comparisonData} barSize={20}>
              <CartesianGrid strokeDasharray="3 3" stroke="#94a3b8" strokeOpacity={0.2} vertical={false} />
              <XAxis dataKey="name" tick={{fill: '#64748b', fontSize: 10}} axisLine={false} tickLine={false} dy={10} interval={0} />
              <YAxis tick={{fill: '#64748b', fontSize: 10}} axisLine={false} tickLine={false} />
              <Tooltip 
                cursor={{fill: 'rgba(255,255,255,0.05)'}}
                contentStyle={{backgroundColor: '#1e293b', border: '1px solid #475569', borderRadius: '12px', color: '#f8fafc', boxShadow: '0 10px 15px -3px rgba(0, 0, 0, 0.5)'}}
                labelStyle={{color: '#94a3b8', marginBottom: '0.5rem'}}
              />
              <Legend wrapperStyle={{paddingTop: '20px', fontSize: '12px'}} />
              <Bar dataKey="استاندارد" fill="#94a3b8" radius={[4, 4, 0, 0]} name="حد استاندارد" />
              {exhausts.map((exhaust, idx) => (
                <Bar 
                  key={exhaust.id} 
                  dataKey={exhaust.name} 
                  fill={[themeColors.primary, '#f59e0b', '#8b5cf6', '#ec4899', '#6366f1'][idx % 5]} 
                  radius={[4, 4, 0, 0]} 
                  name={exhaust.name}
                >
                  {comparisonData.map((entry: any, index: number) => {
                    const value = entry[exhaust.name] as number;
                    const limit = entry['استاندارد'] as number;
                    const { color } = calculateStatus(value, limit);
                    return <Cell key={`cell-${index}`} fill={color} />;
                  })}
                </Bar>
              ))}
            </BarChart>
          </ResponsiveContainer>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import { Send, Bot, User, RefreshCw, MessageSquare, Sparkles, WifiOff } from 'lucide-react';
import { useSettings } from '../contexts/SettingsContext';
import { sendChatMessage, resetChatSession } from '../services/geminiService';

interface Message {
  id: string;
  role: 'user' | 'model';
  text: string;
  timestamp: string;
}

interface ChatBotProps {
  isOnline: boolean;
}

export const ChatBot: React.FC<ChatBotProps> = ({ isOnline }) => {
  const { t, themeColors, dir } = useSettings();
  const [messages, setMessages] = useState<Message[]>([
    {
      id: 'welcome',
      role: 'model',
      text: t('chat.welcome'),
      timestamp: new Date().toLocaleTimeString()
    }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const handleSend = async () => {
    if (!input.trim() || isLoading || !isOnline) return;

    const userMsg: Message = {
      id: Date.now().toString(),
      role: 'user',
      text: input,
      timestamp: new Date().toLocaleTimeString()
    };

    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsLoading(true);

    try {
      const responseText = await sendChatMessage(userMsg.text);
      const botMsg: Message = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: responseText,
        timestamp: new Date().toLocaleTimeString()
      };
      setMessages(prev => [...prev, botMsg]);
    } catch (error) {
      console.error(error);
    } finally {
      setIsLoading(false);
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  const handleReset = () => {
    resetChatSession();
    setMessages([{
      id: Date.now().toString(),
      role: 'model',
      text: t('chat.welcome'),
      timestamp: new Date().toLocaleTimeString()
    }]);
  };

  return (
    <div className="animate-in slide-in-from-bottom-5 duration-500 h-[65dvh] md:h-[600px] flex flex-col w-full max-w-4xl mx-auto shadow-2xl rounded-2xl border border-gray-200 dark:border-slate-700/50">
      <div className="bg-white dark:bg-slate-800/90 backdrop-blur-md rounded-t-2xl p-3 md:p-4 flex justify-between items-center border-b border-gray-100 dark:border-slate-700">
        <div className="flex items-center gap-3">
            <div className="p-2 md:p-3 rounded-xl bg-gradient-to-tr from-purple-500 to-indigo-500 text-white shadow-lg shadow-purple-500/20">
                <Sparkles size={20} className="md:w-6 md:h-6" />
            </div>
            <div>
                <h2 className="text-base md:text-xl font-bold text-slate-800 dark:text-white">{t('nav.chat')}</h2>
                <div className="flex items-center gap-2">
                  <p className="text-[10px] md:text-xs text-slate-500 dark:text-slate-400">Gemini 3 Pro Preview</p>
                  {!isOnline && (
                    <span className="text-[10px] bg-red-100 text-red-600 dark:bg-red-900/30 dark:text-red-400 px-2 py-0.5 rounded-full flex items-center gap-1">
                      <WifiOff size={10} />
                      {t('status.offline')}
                    </span>
                  )}
                </div>
            </div>
        </div>
        <button 
            onClick={handleReset}
            className="p-2 text-slate-500 hover:text-slate-800 dark:text-slate-400 dark:hover:text-white hover:bg-gray-100 dark:hover:bg-white/10 rounded-lg transition-all tooltip"
            title={t('chat.clear')}
        >
            <RefreshCw size={18} className="md:w-5 md:h-5" />
        </button>
      </div>

      <div className="flex-1 bg-white/50 dark:bg-slate-900/50 backdrop-blur-sm overflow-y-auto p-3 md:p-4 space-y-4 custom-scrollbar">
        {messages.map((msg) => (
          <div 
            key={msg.id} 
            className={`flex items-end gap-2 md:gap-3 ${msg.role === 'user' ? 'flex-row-reverse' : 'flex-row'}`}
          >
            <div 
                className={`w-7 h-7 md:w-8 md:h-8 rounded-full flex items-center justify-center shrink-0 ${
                    msg.role === 'user' 
                    ? 'bg-slate-200 dark:bg-slate-700 text-slate-600 dark:text-slate-300' 
                    : 'bg-gradient-to-tr from-purple-500 to-indigo-500 text-white'
                }`}
            >
                {msg.role === 'user' ? <User size={14} className="md:w-4 md:h-4" /> : <Bot size={14} className="md:w-4 md:h-4" />}
            </div>

            <div className={`max-w-[85%] md:max-w-[80%] rounded-2xl p-3 md:p-4 shadow-sm ${
                msg.role === 'user' 
                ? 'bg-white dark:bg-slate-800 text-slate-800 dark:text-slate-200 rounded-br-none border border-gray-200 dark:border-slate-700' 
                : 'bg-white dark:bg-slate-800 text-slate-800 dark:text-slate-200 rounded-bl-none border border-purple-100 dark:border-purple-500/20'
            }`}>
                <div className="whitespace-pre-wrap leading-relaxed text-sm md:text-base">{msg.text}</div>
                <div className="text-[10px] opacity-50 mt-1 md:mt-2 text-right dir-ltr">{msg.timestamp}</div>
            </div>
          </div>
        ))}

        {isLoading && (
            <div className="flex items-center gap-3">
                <div className="w-8 h-8 rounded-full bg-gradient-to-tr from-purple-500 to-indigo-500 text-white flex items-center justify-center shrink-0">
                    <Sparkles size={16} className="animate-pulse" />
                </div>
                <div className="bg-white dark:bg-slate-800 px-4 py-3 rounded-2xl rounded-bl-none border border-purple-100 dark:border-purple-500/20">
                   <div className="flex gap-1">
                      <div className="w-2 h-2 bg-purple-400 rounded-full animate-bounce" style={{animationDelay: '0ms'}}></div>
                      <div className="w-2 h-2 bg-purple-400 rounded-full animate-bounce" style={{animationDelay: '150ms'}}></div>
                      <div className="w-2 h-2 bg-purple-400 rounded-full animate-bounce" style={{animationDelay: '300ms'}}></div>
                   </div>
                </div>
            </div>
        )}
        <div ref={messagesEndRef} />
      </div>

      <div className="bg-white dark:bg-slate-800/90 backdrop-blur-md rounded-b-2xl p-3 md:p-4 border-t border-gray-200 dark:border-slate-700/50">
        <div className="relative flex items-center gap-2">
            <textarea
                value={input}
                onChange={(e) => setInput(e.target.value)}
                onKeyDown={handleKeyDown}
                placeholder={isOnline ? t('chat.placeholder') : t('chat.offlinePlaceholder')}
                disabled={!isOnline}
                rows={1}
                className="w-full bg-gray-100 dark:bg-slate-900/80 border border-gray-200 dark:border-slate-600 rounded-xl px-4 py-3 pr-12 text-slate-900 dark:text-white focus:outline-none focus:ring-2 focus:ring-purple-500 transition-all resize-none overflow-hidden max-h-32 disabled:opacity-50 disabled:cursor-not-allowed text-sm md:text-base"
                style={{ minHeight: '48px' }}
            />
            <button
                onClick={handleSend}
                disabled={!input.trim() || isLoading || !isOnline}
                className="absolute left-2 p-2 bg-purple-600 hover:bg-purple-500 disabled:bg-gray-300 dark:disabled:bg-slate-700 text-white rounded-lg transition-all shadow-lg shadow-purple-500/20"
                style={dir === 'ltr' ? { right: '0.5rem', left: 'auto' } : {}}
            >
                {isLoading ? <RefreshCw size={18} className="animate-spin" /> : <Send size={18} className={dir === 'rtl' ? 'rotate-180' : ''} />}
            </button>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useRef } from 'react';
import { FileText, Save, RefreshCcw, PlusCircle, Settings, Factory, Calendar, Download, Upload, Database } from 'lucide-react';
