            <div>
                 <h2 className="text-2xl font-bold text-slate-800 dark:text-white mb-1">{selectedExhaust.name}</h2>
                 <p className="text-slate-500 dark:text-slate-400 flex items-center gap-2">
                    <MapPin size={16} />
                    {t('location')}: {selectedExhaust.location}
