                    <Tooltip content={<CustomTooltip />} />
                    <Legend wrapperStyle={{fontSize: '12px'}} />
                    <Area type="monotone" dataKey="O2" name="O2 (%)" stroke={themeColors.primary} fillOpacity={1} fill="url(#colorO2Details)" strokeWidth={3} />
                  </AreaChart>
                </ResponsiveContainer>
              </div>
            </div>
        </div>

        {/* History Table */}
